import React, { useEffect, useState } from 'react';
import * as adminServiceModule from '../services/adminService';
import * as logServiceModule from '../services/logService';
import * as authServiceModule from '../services/authService';
import axios from 'axios';

export default function AdminDashboard() {
  const [mode, setMode] = useState('local');
  const [loadingMode, setLoadingMode] = useState(true);
  const [changing, setChanging] = useState(false);
  const [recentLogs, setRecentLogs] = useState([]);

  // safe token getter
  const getToken = () => {
    try {
      if (authServiceModule && typeof authServiceModule.getToken === 'function') return authServiceModule.getToken();
      if (authServiceModule && typeof authServiceModule.default === 'object' && typeof authServiceModule.default.getToken === 'function') return authServiceModule.default.getToken();
    } catch (e) { /* ignore */ }
    return localStorage.getItem('token');
  };
  const token = getToken();

  // safe wrapper to call admin service or fallback to fetch
  const fetchStorageMode = async () => {
    try {
      if (adminServiceModule && typeof adminServiceModule.getStorageMode === 'function') {
        return await adminServiceModule.getStorageMode(token);
      }
      if (adminServiceModule && adminServiceModule.default && typeof adminServiceModule.default.getStorageMode === 'function') {
        return await adminServiceModule.default.getStorageMode(token);
      }
      // fallback HTTP call
      const API = process.env.REACT_APP_API_BASE || 'http://localhost:5000';
      const res = await axios.get(`${API}/admin/storage-mode`, { headers: { Authorization: `Bearer ${token}` } });
      return res.data;
    } catch (err) {
      console.error('fetchStorageMode error', err);
      return { mode: process.env.REACT_APP_DEFAULT_STORAGE || 'local' };
    }
  };

  const updateStorageMode = async (newMode) => {
    try {
      if (adminServiceModule && typeof adminServiceModule.setStorageMode === 'function') {
        return await adminServiceModule.setStorageMode(token, newMode);
      }
      if (adminServiceModule && adminServiceModule.default && typeof adminServiceModule.default.setStorageMode === 'function') {
        return await adminServiceModule.default.setStorageMode(token, newMode);
      }
      const API = process.env.REACT_APP_API_BASE || 'http://localhost:5000';
      const res = await axios.post(`${API}/admin/storage-mode`, { mode: newMode }, { headers: { Authorization: `Bearer ${token}` } });
      return res.data;
    } catch (err) {
      console.error('updateStorageMode error', err);
      throw err;
    }
  };

  const fetchLogs = async () => {
    try {
      if (logServiceModule && typeof logServiceModule.getRecentLogs === 'function') {
        const r = await logServiceModule.getRecentLogs(token, 10);
        return r?.logs || r || [];
      }
      if (logServiceModule && typeof logServiceModule.getLogs === 'function') {
        const r = await logServiceModule.getLogs(token, 10);
        return r?.logs || r || [];
      }
      if (logServiceModule && logServiceModule.default && typeof logServiceModule.default.getLogs === 'function') {
        const r = await logServiceModule.default.getLogs(token, 10);
        return r?.logs || r || [];
      }
      // fallback HTTP
      const API = process.env.REACT_APP_API_BASE || 'http://localhost:5000';
      const res = await axios.get(`${API}/logs/recent?limit=10`, { headers: { Authorization: `Bearer ${token}` } });
      return res.data?.logs || res.data || [];
    } catch (err) {
      console.error('fetchLogs error', err);
      return [];
    }
  };

  useEffect(() => {
    let mounted = true;
    (async () => {
      try {
        const res = await fetchStorageMode();
        if (mounted) setMode(res.mode || 'local');
      } finally {
        if (mounted) setLoadingMode(false);
      }
    })();

    (async () => {
      const logs = await fetchLogs();
      if (mounted) setRecentLogs(logs);
    })();

    return () => { mounted = false; };
  }, [token]);

  const toggleStorage = async () => {
    const newMode = mode === 'local' ? 'azure' : 'local';
    setChanging(true);
    try {
      await updateStorageMode(newMode);
      setMode(newMode);
    } catch (err) {
      alert('Failed to change storage mode: ' + (err.response?.data?.error || err.message));
    } finally {
      setChanging(false);
    }
  };

  return (
    <div className="p-6 max-w-6xl mx-auto">
      <header className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-3xl font-bold text-slate-800">Admin Dashboard</h1>
          <p className="text-sm text-slate-500">Manage storage, users and monitor recent activity</p>
        </div>
        <div className="flex items-center gap-4">
          <div className="text-sm text-slate-600 mr-2">Storage</div>
          <div className="flex items-center gap-3">
            <div className="px-3 py-1 rounded bg-slate-100 text-slate-700 text-xs">{loadingMode ? 'Loading...' : mode.toUpperCase()}</div>
            <button
              onClick={toggleStorage}
              disabled={changing || loadingMode}
              className={`relative inline-flex items-center h-8 w-14 rounded-full transition-colors ${mode === 'azure' ? 'bg-blue-600' : 'bg-gray-300'} ${changing ? 'opacity-60 cursor-wait' : 'cursor-pointer'}`}
              aria-label="Toggle storage mode"
            >
              <span
                className={`inline-block bg-white rounded-full h-6 w-6 transform transition-transform ${mode === 'azure' ? 'translate-x-6' : 'translate-x-1'}`}
              />
            </button>
          </div>
        </div>
      </header>

      <section className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
        <div className="bg-white shadow rounded-lg p-4">
          <h3 className="text-sm text-slate-500">Active Storage</h3>
          <div className="mt-3 flex items-center justify-between">
            <div>
              <div className="text-lg font-semibold text-slate-800">{mode === 'azure' ? 'Azure Blob Storage' : 'Local Disk'}</div>
              <div className="text-xs text-slate-500 mt-1">{mode === 'azure' ? 'Using Azure container for blobs' : 'Files served from local uploads directory'}</div>
            </div>
            <div className="text-right">
              <div className="text-2xl font-bold text-slate-800">{mode === 'azure' ? 'Cloud' : 'Local'}</div>
            </div>
          </div>
        </div>

        <div className="bg-gradient-to-br from-indigo-500 to-purple-600 text-white shadow-lg rounded-lg p-4">
          <h3 className="text-sm opacity-90">Quick Actions</h3>
          <div className="mt-4 flex flex-col gap-3">
            <a href="/upload" className="bg-white/20 hover:bg-white/30 transition rounded px-3 py-2 text-sm">Upload File</a>
            <a href="/users" className="bg-white/20 hover:bg-white/30 transition rounded px-3 py-2 text-sm">Manage Users</a>
            <a href="/logs" className="bg-white/20 hover:bg-white/30 transition rounded px-3 py-2 text-sm">View Logs</a>
          </div>
        </div>

        <div className="bg-white shadow rounded-lg p-4">
          <h3 className="text-sm text-slate-500">Usage</h3>
          <div className="mt-3">
            <div className="text-3xl font-semibold text-slate-800">—</div>
            <div className="text-xs text-slate-500 mt-1">Storage/Transfer metrics will appear here.</div>
          </div>
        </div>
      </section>

      <section className="bg-white shadow rounded-lg p-4">
        <div className="flex items-center justify-between mb-3">
          <h3 className="text-lg font-semibold text-slate-800">Recent Activity</h3>
          <div className="text-sm text-slate-500">Last 10 events</div>
        </div>

        <div className="divide-y">
          {recentLogs.length === 0 && (
            <div className="py-6 text-center text-slate-400">No recent activity to show.</div>
          )}

          {recentLogs.map((log, i) => (
            <div key={i} className="flex items-start gap-4 py-3">
              <div className="w-10">
                <div className="h-10 w-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-600 font-semibold">
                  {log.user_email ? String(log.user_email).charAt(0).toUpperCase() : 'U'}
                </div>
              </div>
              <div className="flex-1">
                <div className="text-sm text-slate-800">
                  <span className="font-medium">{log.user_email || 'Unknown'}</span>
                  <span className="text-slate-500"> — {log.action || log.type || 'action'}</span>
                </div>
                <div className="text-xs text-slate-400 mt-1">{new Date(log.timestamp || log.created_at || Date.now()).toLocaleString()}</div>
              </div>
              <div className="text-xs text-slate-400">{log.file_id ? `File: ${log.file_id}` : ''}</div>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
}
